// Que hace: agrega la Revision Corporal Periodica a la app.
//
// IMPORTANTE: antes de correr este script, ejecutar el SQL en Supabase:
// 10_revision_corporal.sql (crea la tabla revisiones_corporales con RLS)
//
//   1) app/revision-corporal/page.tsx (ARCHIVO NUEVO) -- pantalla con
//      el checklist de 7 puntos (orejas, ojos, boca, patitas, cuello,
//      piel, pancita). Flujo: items uno a uno con avance automatico al
//      marcar, pantalla final que muestra lo encontrado y permite
//      guardar con o sin observacion en Prevencion.
//
//   2) app/dashboard/page.tsx (REEMPLAZA el existente) -- agrega la
//      consulta de la ultima revision corporal. Si la mascota tiene 5+
//      anos y han pasado mas del intervalo (90 dias para Adulto/Adulto
//      Maduro, 30 dias para Senior), aparece la tarjeta "🔍 Revision
//      corporal" en Proximos, clickeable para iniciar la revision.
//
//   3) components/DashboardContenido.tsx (REEMPLAZA el existente) --
//      actualiza la interfaz para que las tarjetas de Proximos puedan
//      ser clickeables (campo url opcional), y muestra "Tocar para
//      iniciar" en la tarjeta de revision corporal.
//
// Como correrlo: node generar_70_revision_corporal.js
// Confirma "OK" para los 3 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/revision-corporal/page.tsx', "");
escribir('app/dashboard/page.tsx', "");
escribir('components/DashboardContenido.tsx', "");
